import 'package:equatable/equatable.dart';

class UserState extends Equatable {
  final String name;
  final int age;
  final bool isLoading;

  const UserState({
    required this.name,
    required this.age,
    this.isLoading = false,
  });

  UserState copyWith({
    String? name,
    int? age,
    bool? isLoading,
  }) {
    return UserState(
      name: name ?? this.name,
      age: age ?? this.age,
      isLoading: isLoading ?? this.isLoading,
    );
  }

  @override
  List<Object?> get props => [name, age, isLoading];
}

