import 'package:flutter/material.dart';
import 'package:flutter_bloc/flutter_bloc.dart';
import 'package:equatable/equatable.dart';

void main() => runApp(MyApp());

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      home: BlocProvider(
        create: (_) => UserBloc(),
        child: UserPage(),
      ),
    );
  }
}

// ---------- State ----------
class UserState extends Equatable {
  final String name;
  final int age;
  final bool isLoading;
  final String? error;

  const UserState({
    this.name = 'John',
    this.age = 25,
    this.isLoading = false,
    this.error,
  });

  UserState copyWith({
    String? name,
    int? age,
    bool? isLoading,
    String? error,
  }) {
    return UserState(
      name: name ?? this.name,
      age: age ?? this.age,
      isLoading: isLoading ?? this.isLoading,
      error: error ?? this.error,
    );
  }

  @override
  List<Object?> get props => [name, age, isLoading, error];
}

// ---------- Events ----------
abstract class UserEvent extends Equatable {
  const UserEvent();
  @override List<Object?> get props => [];
}

class UpdateName extends UserEvent {
  final String name;
  const UpdateName(this.name);
}

class IncrementAge extends UserEvent {}
class LoadData extends UserEvent {}

// ---------- BLoC ----------
class UserBloc extends Bloc<UserEvent, UserState> {
  UserBloc() : super(const UserState()) {
    on<UpdateName>((event, emit) {
      emit(state.copyWith(name: event.name));
    });
    on<IncrementAge>((event, emit) {
      emit(state.copyWith(age: state.age + 1));
    });
    on<LoadData>((event, emit) async {
      emit(state.copyWith(isLoading: true, error: null));
      await Future.delayed(Duration(seconds: 1));
      // Simulate success
      emit(state.copyWith(isLoading: false));
      // Simulate error (uncomment to test)
      // emit(state.copyWith(isLoading: false, error: 'Failed to load'));
    });
  }
}

// ---------- UI ----------
class UserPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('copyWith Demo')),
      body: BlocBuilder<UserBloc, UserState>(
        builder: (context, state) {
          if (state.isLoading) {
            return Center(child: CircularProgressIndicator());
          }
          if (state.error != null) {
            return Center(child: Text('Error: ${state.error}'));
          }
          return Padding(
            padding: const EdgeInsets.all(16.0),
            child: Column(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                Text('Name: ${state.name}', style: TextStyle(fontSize: 24)),
                Text('Age: ${state.age}', style: TextStyle(fontSize: 24)),
                SizedBox(height: 20),
                Row(
                  mainAxisAlignment: MainAxisAlignment.center,
                  children: [
                    ElevatedButton(
                      onPressed: () => context.read<UserBloc>().add(IncrementAge()),
                      child: Text('+1 Age'),
                    ),
                    SizedBox(width: 10),
                    ElevatedButton(
                      onPressed: () {
                        // Show dialog to change name
                        showDialog(
                          context: context,
                          builder: (_) => AlertDialog(
                            title: Text('Change Name'),
                            content: TextField(
                              onSubmitted: (value) {
                                context.read<UserBloc>().add(UpdateName(value));
                                Navigator.pop(context);
                              },
                            ),
                            actions: [
                              TextButton(
                                onPressed: () => Navigator.pop(context),
                                child: Text('Cancel'),
                              ),
                            ],
                          ),
                        );
                      },
                      child: Text('Change Name'),
                    ),
                    SizedBox(width: 10),
                    ElevatedButton(
                      onPressed: () => context.read<UserBloc>().add(LoadData()),
                      child: Text('Reload'),
                    ),
                  ],
                ),
              ],
            ),
          );
        },
      ),
    );
  }
}
